public int[] popcountDepth(long[] nums, int[][] queries) {
    int[] answer = new int[queries.length];
    int index = 0;
    for (int[] query : queries) {
        if (query[0] == 1) {
            int count = 0;
            for (int i = query[1]; i <= query[2]; i++) {
                long num = nums[i];
                int depth = 0;
                while (num != 1) {
                    num = Long.bitCount(num);
                    depth++;
                }
                if (depth == query[3]) {
                    count++;
                }
            }
            answer[index++] = count;
        } else {
            nums[query[1]] = query[2];
        }
    }
    return answer;
}
